import React from "react";
import { useNavigate } from "react-router-dom";

const green = "#0f9d58";
const lightGreen = "#eaf8f0";

export default function Settings({ employee }) {
  const navigate = useNavigate();

  if (!employee)
    return (
      <div style={outer}>
        <div style={center}>
          <p>Please login again.</p>
        </div>
      </div>
    );

  return (
    <div style={outer}>
      <div style={card}>

        {/* HEADER */}
        <div style={headerRow}>
          <button style={backBtn} onClick={() => navigate("/home")}>
            ⬅ Back
          </button>
          <h2 style={title}>Settings</h2>
        </div>

        {/* EMPLOYEE INFO */}
        <p style={empInfo}>
          {employee.name} • {employee.empld}
        </p>

        {/* SETTINGS CARDS */}
        <div style={cardsWrapper}>

          {/* PROFILE SETTINGS */}
          <div style={settingCard} onClick={() => navigate("/settings/profile")}>
            <h3 style={cardTitle}>Profile Settings</h3>
            <p style={cardText}>Update name, email & profile details</p>
          </div>

          {/* CHANGE PASSWORD */}
          <div style={settingCard} onClick={() => navigate("/settings/change-password")}>
            <h3 style={cardTitle}>Change Password</h3>
            <p style={cardText}>Update your account password</p>
          </div>

          {/* THEME SETTINGS */}
          <div style={settingCard} onClick={() => navigate("/settings/theme")}>
            <h3 style={cardTitle}>Theme Settings</h3>
            <p style={cardText}>Switch between light & dark mode</p>
          </div>

          {/* NOTIFICATIONS */}
          <div style={settingCard} onClick={() => navigate("/settings/notifications")}>
            <h3 style={cardTitle}>Notifications</h3>
            <p style={cardText}>Control app alerts & reminders</p>
          </div>

          {/* LOGOUT */}
          <div style={logoutCard} onClick={() => navigate("/")}>
            <h3 style={logoutTitle}>Logout</h3>
            <p style={logoutText}>Sign out from this device</p>
          </div>

        </div>
      </div>
    </div>
  );
}

// ---------- STYLES ----------
const outer = {
  minHeight: "100vh",
  background: lightGreen,
  padding: 20,
  fontFamily: "Segoe UI",
};

const center = { textAlign: "center", padding: 40 };

const card = {
  maxWidth: 950,
  margin: "0 auto",
  background: "#fff",
  padding: 20,
  borderRadius: 16,
  boxShadow: "0 6px 20px rgba(0,0,0,0.12)",
};

const headerRow = { display: "flex", alignItems: "center", gap: 10 };

const backBtn = {
  background: "none",
  border: "none",
  color: green,
  fontSize: 16,
  cursor: "pointer",
};

const title = { color: green, margin: 0 };

const empInfo = { fontSize: 13, marginTop: 6, color: "#555" };

const cardsWrapper = {
  display: "flex",
  flexDirection: "column",
  gap: 16,
  marginTop: 20,
};

const settingCard = {
  padding: 18,
  borderRadius: 12,
  border: "1px solid #e1f5e8",
  background: "#f9fffb",
  cursor: "pointer",
  transition: "0.2s",
};

const cardTitle = { color: green, margin: "0 0 6px 0" };
const cardText = { margin: 0, fontSize: 13, color: "#555" };

const logoutCard = {
  padding: 18,
  borderRadius: 12,
  border: "1px solid #ffcccc",
  background: "#fff5f5",
  cursor: "pointer",
};

const logoutTitle = { color: "#c62828", margin: 0 };
const logoutText = { fontSize: 13, color: "#c62828" };
